mapper.select:
SELECT 
FROM im_user_conversation uc
INNER JOIN im_conversation c ON uc.conversation_id = c.id
WHERE uc.user_id = #{userId}
AND uc.status = 1
AND c.status = 1
ORDER BY uc.is_top DESC, c.last_message_time DESC

    OFFSET #{offset}


    LIMIT #{limit}

mapper.update:
UPDATE im_user_conversation
SET unread_count = unread_count + 1,
    update_time = #{updateTime}
WHERE user_id = #{userId}
  AND conversation_id = #{conversationId}
  AND status = 1
